import axios from "axios";
import { Feature } from "ol";
import { endpoints } from "./endpoints";
import { guid } from "../constants";
import { format } from "../constants";

export const getPopulationOnFeatures = async (features: Feature[]) => {
  const res = await axios.get(endpoints.batchAreaStatistics, {
    params: {
      geojson: format.writeFeatures(features),
      guid,
    },
  });
  return res.data.population_rsv;
};
