import { observable, action } from "mobx";
import { getPopulationOnFeatures } from "../../api/population-api/population-api";
import { Feature } from "ol";
import { toast } from "react-toastify";

export class PopulationService {
  @observable currentPolygonPopulation: number = -1;

  @action
  public async getNewPopulation(features: Feature[]) {
    getPopulationOnFeatures(features)
      .then((res) => {
        this.currentPolygonPopulation = res;
      })
      .catch(() => {
        this.currentPolygonPopulation = -1;
        toast.error("Слишком маленький полигон.");
      });
  }
}
