import React, { useEffect, useRef, useState } from "react";
import { Draw, Modify } from "ol/interaction";
import s from "./styles.module.scss";
import { ReactComponent as Trash } from "./../../assets/icons/trash.svg";
import { ReactComponent as Pencil } from "./../../assets/icons/pencil.svg";
import { map, overlay, source } from "./map-constants";
import GeometryType from "ol/geom/GeometryType";
import { getCenterOfPolygon } from "../../helpers/functions";
import { useInstance } from "react-ioc";
import { PopulationService } from "../../services/population-service/population-service";
import { observer } from "mobx-react";

export const Map = observer(() => {
  const refMap = useRef<HTMLDivElement>(null);
  const refOverlay = useRef<HTMLDivElement>(null);
  const populationService = useInstance(PopulationService);
  const [isPolygonExist, setIsPolygonExist] = useState<boolean>(false);
  const [isDraw, setIsDraw] = useState<boolean>(true);
  const [draw, setDraw] = useState<Draw>();
  const modify = new Modify({
    source,
  });

  useEffect(() => {
    map.setTarget(refMap.current || undefined);
    overlay.setElement(refOverlay.current || undefined);
    initiateDraw();
    initiateModify();
  }, []);

  const initiateDraw = () => {
    const newDraw = new Draw({
      type: GeometryType.POLYGON,
      source,
    });
    newDraw.on("drawend", (e) => {
      map.removeInteraction(newDraw);
      e.feature.setId("polygon");
      setIsPolygonExist(true);
      overlay.setPosition(getCenterOfPolygon(e.feature));
      populationService.getNewPopulation([e.feature]);
    });
    map.addInteraction(newDraw);
    setDraw(newDraw);
  };

  const removeDraw = () => {
    if (draw) {
      map.removeInteraction(draw);
    }
  };

  const initiateModify = () => {
    map.addInteraction(modify);
    modify.on("modifyend", (e) => {
      overlay.setPosition(getCenterOfPolygon(e.features.getArray()[0]));
      populationService.getNewPopulation(e.features.getArray());
    });
  };

  const deletePolygon = () => {
    if (isPolygonExist) {
      source.removeFeature(source.getFeatureById("polygon"));
      setIsPolygonExist(false);
      overlay.setPosition(undefined);
      populationService.currentPolygonPopulation = -1;
      if (isDraw) {
        initiateDraw();
      }
    }
  };

  const drawToggle = () => {
    if (isDraw) {
      removeDraw();
    } else if (!isPolygonExist) {
      initiateDraw();
    }
    setIsDraw(!isDraw);
  };

  return (
    <div className={s.mapContainer}>
      <div ref={refMap} className={s.map} />
      <div className={s.rightGroup}>
        <div ref={refOverlay} className={s.popup}>
          {populationService.currentPolygonPopulation !== -1 ? populationService.currentPolygonPopulation : "..."}
          <button onClick={deletePolygon} title="Удалить полигон">
            x
          </button>
        </div>
        <button onClick={drawToggle} className={isDraw ? s.active : ""} title="Рисовать/не рисовать полигон">
          <Pencil />
        </button>
        {isPolygonExist && (
          <button onClick={deletePolygon} title="Удалить полигон">
            <Trash />
          </button>
        )}
      </div>
    </div>
  );
});
